import React from 'react';
import '../App.css';
import {
  Container, Row, Col,
  ToggleButtonGroup, ToggleButton,
  ButtonGroup, ButtonToolbar, Button,
  InputGroup, FormControl,
  Navbar, Nav, Form,
  Modal, Tab,

} from 'react-bootstrap';
import PropTypes from 'prop-types';
import Clock from 'react-digital-clock';
import GridLoader from 'react-spinners/GridLoader'; // https://www.react-spinners.com/
import PropagateLoader from 'react-spinners/PropagateLoader';
import DatePicker from 'react-date-picker';
import packageJson from '../../package.json';
import JobTable from './JobTable';
import { DataContext } from '../data-context';
import { Doughnut } from 'react-chartjs-2';
import { JobForm } from '../forms/JobForm';
import { WorkForm } from '../forms/WorkForm';
import User from './User';
import Line from './Line';
import Machine from './Machine';
import DailyReport from '../reports/DailyReport';
import moment from 'moment'; // https://momentjs.com/
// https://github.com/jerairrest/react-chartjs-2
// https://www.chartjs.org/docs/latest/charts/doughnut.html
import { css } from '@emotion/core';

const util = require('../util.js');

const override = css`
    display: block;
    margin: 0 auto;
    border-color: red;
`;

export default class Dashboard extends React.Component {

  static contextType = DataContext;
  static propTypes = {
    onLogOut: PropTypes.func,
    isAdmin: PropTypes.bool
  };


  constructor(...args) {
    super(...args);
    console.log("Dashboard Context:", this.context);
    this.state = {
      // ...this.context,
      // data: this.context.data,
      showJobForm: false,
      showWorkForm: false,
      showReportSetup: false,
      // ___showDatePickerForm: false, 

      // showJobForm: true,
      tab: '#home',
      // tab: '#users',
      loading: true,
      users: this.props.users,

      //------ Report
      showReport: true,
      fromDate: new Date(),
      toDate: new Date(),
      report: 'kpi-breakdown-rate',
      report: 'kpi-breakdown-rate-table',
      report: 'kpi-breakdown-rate-graph',
      report: 'kpi-breakdown-time-table',
      report: 'kpi-mean-time-to-repair-machine',
      report: 'kpi-mean-time-to-repair-machine-top5',
      report: 'kpi-mean-time-between-failure',
      report: 'kpi-mean-time-between-failure-top5',
      report: 'kpi-data-equipment-type',
      report: 'kpi-working-time-for-personal',

      //------ Test
      // showReport: true,
      // fromDate: '2019-12-01', toDate: '2019-12-31',  // December
      // fromDate: '2019-03-01', toDate: '2019-03-31', // March
      fromDate: '2019-03-01', toDate: '2019-03-02', // One day
      // report: 'daily',
    };
  }

  handleNavSelect = (k, e) => {
    console.log('handleNavSelect', k);
    if (k === '#logout') {
      this.handleLogOut();
      return;
    }
    if (this.props.loading) return; // Guard, don't change page until all data is loaded.
    this.setState({ tab: k });
  }

  showReport = () => {
    console.log('Show Report ',this.state.report)
    if (this.state.report !== '') {
      this.setState({ showReport: true })
    }
  }
  setShowJobForm = (show) => this.setState({ showJobForm: show });
  setShowWorkForm = (show) => this.setState({ showWorkForm: show });
  setDatePickerForm = (show) => this.setState({ showDatePickerForm: show });
  setShowDailyReport = (show) => this.setState({
    showReport: show,
    report: show ? 'daily' : '',
  });

  setShowKPIReport = (show) => this.setState({
    showReport: show,
    report: 'kpi',
  });

  setShowReportSetup = (show) => this.setState({ showReportSetup: show });
  setToday = () =>
    this.setState({
      fromDate: new Date(),
      toDate: new Date(),
    })


  handleLogOut = () => {
    this.props.onLogOut()
  }
  handleJobClick = (event, job) => {
    if (this.props.loading) return;
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: true,
      showWorkForm: false,
      showReport: false,
      showReportSetup: false,
      createMachineJob: false,
      theJob: job,

    });
  }

  handleWorkClick = (event, job) => {
    if (this.props.loading) return;
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: false,
      showWorkForm: true,
      createMachineJob: false,
      theJob: job
    });
  }

  handleViewWorkClick = (event, job) => {
    if (this.props.loading) return;
    console.log('handleJobClick', event, job)
    this.setState({
      showJobForm: false,
      showWorkForm: true,
      createMachineJob: false,
      theJob: job
    });
  }


  handlePrepareReport = (e) => {
    // console.log('handlePrepareReport:', this.state.showDatePickerForm)
    // this.setState({ showDatePickerForm: true })
    // this.setState({ showReport: true })
    this.setState({
      showReportSetup: true,
      report: ''
    })
  }

  handleCreateMachineJob = (e) => {
    this.setState({
      showJobForm: true,
      createMachineJob: true,
      theJob: { state: -1 }
    })
  }

  handleReportChange = (val ) => {
    console.log('handleReportChange',val )
    this.setState({
      report: val,
      showReport: false,
    })
  }


  handleCloseWorkForm = (reload = false) => {
    if (reload) {
      // console.log("Reload parts....", reload)
      let lineCode = this.context.mainLine ? this.context.mainLine.code : null
      util.fetchJobs(lineCode)
        .then(res =>
          this.setState({
            jobs: res.data,
            showWorkForm: false
          })
        )
    } else {
      this.setState({
        showWorkForm: false
      })
    }
  }

  handleCloseJobForm = (reload = false) => {
    if (reload) {
      // console.log("Reload parts....", reload)
      let lineCode = this.context.mainLine ? this.context.mainLine.code : null
      util.fetchJobs(lineCode)
        .then(res =>
          this.setState({
            jobs: res.data,
            showJobForm: false,
            createMachineJob: false
          })
        )
    } else {
      this.setState({
        showJobForm: false,
        createMachineJob: false
      })
    }
  }

  // maybe used for general job
  __handleCreateGeneralJob = (e) => {
    this.setState({
      showJobForm: true,
      createGeneralJob: true
    })
  }

  handleFromDateChange = (date) => {
    if (moment(this.state.toDate).isSameOrAfter(date)) {
      this.setState({ fromDate: date });
    } else {
      this.setState({
        fromDate: date,
        toDate: date
      })
    }
  }
  handleToDateChange = (date) => {
    if (moment(this.state.fromDate).isSameOrBefore(date))
      this.setState({ toDate: date });
  }


  UNSAFE_componentWillMount() {
    console.log('UNSAFE_componentWillMount')
    if (this.context.mainLine.code.startsWith('__')) {
      this.setState({
        mainLine: ''
      })
    }

    let _this = this;

    if (process.env.NODE_ENV === 'production') {
      // Only periodically fetch data in production
      setInterval(function () {
        console.log("***Interval fetchJob()***")
        let lineCode = this.context.mainLine ? this.context.mainLine.code : null
        util.fetchJobs(lineCode)
          .then(res =>
            _this.setState({
              jobs: res.data
            },
              () => {
                _this.context.jobs = res.data
              })
          )
      }, 60000);
    }

    let lineCode = this.context.mainLine ? this.context.mainLine.code : null
    util.fetchJobs(lineCode)
      .then(res =>
        this.setState({
          jobs: res.data
        })
      )

    return;
    let data = this.state.data;
    data['jobs'] = util.fetchJobs();
    this.context.data = data['jobs']
    console.log("data['jobs']", data['jobs'])
    this.setState({ data: data });
    this.setState({ jobs: data['jobs'] });
    // document.addEventListener("keydown", this._handleKeyDown);
  }

  render() {
    // let data = this.context.data;
    // let data = this.state.data;
    let jobs = this.state.jobs;

    // Sample Chart
    const chartData = {
      labels: ['Backlog', 'WIP', 'Done'],
      datasets: [{
        data: [300, 50, 100],
        backgroundColor: ['#FF4242', '#4242FF', '#42FF42'],
        hoverBackgroundColor: ['#FF0000', '#0000FF', '#00FF00'],
        borderWidth: [1, 1, 1]
      }]
    };

    const chartOptions = {
      legend: {
        display: false,
      }
    };

    const jobs0 = [];
    const jobs1 = [];
    const jobs2 = [];
    const jobs3 = [];
    // console.log(jobs);
    // if (typeof (data) === 'array')
    //   console.log("data", data)

    if (jobs !== undefined && Promise.resolve(jobs) !== jobs) {
      // console.log('jobs.data', jobs)
      jobs.forEach((v, i) => {
        // console.log('v.state', v.state)

        switch (v.state) {
          case 0:
            jobs0.push(v);
            break;
          case 1:
            jobs1.push(v);
            break;
          case 2:
            jobs2.push(v);
            break;
          case 3:
            jobs3.push(v);
            break;
          // default:
          // code block
        }
      });
    }


    if (this.state.showReport && this.state.report === 'daily') {
      return (
        <DataContext.Provider value={this.context}>
          <DailyReport
            startDate={moment(this.state.fromDate).format('YYYY-MM-DD')}
            endDate={moment(this.state.toDate).format('YYYY-MM-DD')}
            onClose={() => this.setShowDailyReport(false)} />
        </DataContext.Provider>
      )
    } else {
      let mainLine = this.context.mainLine;
      let user = this.context.mainUser;
      let userName = null;
      if (this.context.mainLine && this.context.mainLine.code.startsWith('_')) {
        // User login (not Line access)
        mainLine = ''
        // guard
        if (user)
          userName = user.name
      }
      return (
        <>
          <DataContext.Provider value={this.context}>
            <Navbar bg="dark" variant="dark" sticky="top" onSelect={this.handleNavSelect}>
              <Navbar.Brand href="#home">
                HLT Repair {mainLine}
              </Navbar.Brand>
              {this.props.isAdmin &&

                <Nav className="mr-auto">
                  <Nav.Link href="#home">Dashboard</Nav.Link>
                  <Nav.Link href="#users" >Users</Nav.Link>
                  <Nav.Link href="#machines" >Machines</Nav.Link>
                  <Nav.Link href="#lines" >Lines</Nav.Link>
                  <Nav.Link href="#help">Help</Nav.Link>
                </Nav>
              }
              <Nav className="mr-auto">
                <GridLoader
                  css={override}
                  sizeUnit={"px"}
                  size={8}
                  color={'#4A90E2'}
                  loading={this.props.loading}
                />
              </Nav>
              <Nav className="mr-auto">
                <Clock />
              </Nav>
              <Form inline style={{ color: '#eeeeee' }}>
                {this.props.isAdmin &&
                  <>
                    <Button disabled={this.props.loading} variant="outline-info" onClick={this.handlePrepareReport}>Report</Button>
                  </>
                }
                <Button disabled={this.props.loading} variant='danger' onClick={this.handleCreateMachineJob}>Machine Repair</Button>
              </Form>
            </Navbar>
            <Navbar bg="dark" variant="dark" fixed="bottom" >
              <Nav className="mr-auto">
                <div style={{ color: '#aaaaaa' }}>Software Version {packageJson.version}-{process.env.NODE_ENV}</div>
              </Nav>
              {userName &&
                <span style={{ color: '#aaaaaa' }}>
                  [{userName}]&nbsp;
              </span>
              }
              <Button variant="outline-light" onClick={this.handleLogOut}>Log Out</Button>
            </Navbar>

            {this.state.tab === '#users' &&
              <Container fluid style={{ marginTop: '00pt' }}>
                <User loading={this.props.loading} data={this.context.users} />
              </Container>
            }
            {this.state.tab === '#lines' &&
              <Container fluid style={{ marginTop: '00pt' }}>
                <Line loading={this.props.loading} data={this.context.lines} />
              </Container>
            }
            {this.state.tab === '#machines' &&
              <Container fluid style={{ marginTop: '00pt' }}>
                <Machine loading={this.props.loading} data={this.context.machines} />
              </Container>
            }

            {this.state.tab === '#home' &&
              <Container fluid style={{ marginTop: '00pt' }}>
                <Row className="db-top">
                  <Col lg={4}>
                    <JobTable
                      backlog
                      title="แจ้งซ่อม"
                      data={jobs0}
                      handleJobClick={this.handleJobClick}
                    />
                  </Col>
                  <Col lg={4}>
                    <JobTable
                      wip
                      title="อยู่ระหว่างซ่อม"
                      data={jobs1}
                      handleJobClick={this.handleJobClick}
                    />
                  </Col>
                  <Col lg={4}>
                    <JobTable
                      done
                      title="รอรายละเอียดงาน"
                      data={jobs2}
                      handleJobClick={this.handleWorkClick}
                      _handleJobClick={this.handleViewWorkClick}
                    />
                  </Col>
                </Row>


              </Container>
            }


            {/* <Row>
              <Col lg={3} style={{ verticalAlign: 'text-top' }}>
                <Row style={{ height: 240 }}>
                  <Doughnut data={chartData} options={chartOptions} />
                </Row>
                <Row style={{ alignContent: 'center' }}>
                  <Button size="lg" variant='danger' block onClick={this.handleCreateMachineJob}>Machine Repair</Button>
                </Row>
              </Col>
              <Col>
              </Col>
            </Row> */}
            <Modal
              show={this.state.showDatePickerForm}
              onHide={() => this.setDatePickerForm(false)}
              size="lg"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>เลือกช่วงเวลา</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <Row>

                  From:
              <DatePicker
                    format="dd/MM/y"
                    onChange={this.handleFromDateChange}
                    value={this.state.fromDate} />
                  To:
              <DatePicker
                    format="dd/MM/y"
                    onChange={this.handleToDateChange}
                    value={this.state.toDate} />
                </Row>
              </Modal.Body>
              <Modal.Footer>
              </Modal.Footer>
            </Modal>

            <Modal
              show={this.state.showJobForm}
              onHide={() => this.setShowJobForm(false)}
              size="md"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>แจ้งซ่อมเครื่องจักร</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <JobForm
                  // viewJob={false}
                  // createMachineJob={this.state.createMachineJob}
                  // createGeneralJob={this.state.createGeneralJob}
                  handleClose={this.handleCloseJobForm}
                  data={this.state.theJob} />
              </Modal.Body>
              {process.env.NODE_ENV === 'development' &&
                <Modal.Footer>
                  _id {this.state.theJob && <span>{this.state.theJob._id} state: {this.state.theJob.state}</span>}
                </Modal.Footer>
              }
            </Modal>

            <Modal
              show={this.state.showWorkForm}
              onHide={() => this.setShowWorkForm(false)}
              size="lg"
              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>งานซ่อมเครื่องจักร</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <WorkForm
                  handleClose={this.handleCloseWorkForm}
                  data={this.state.theJob} />
              </Modal.Body>
              <Modal.Footer>
                _id {this.state.theJob && <span>{this.state.theJob._id} state: {this.state.theJob.state}</span>}
              </Modal.Footer>
            </Modal >

            <Modal
              show={this.state.showReportSetup}
              onHide={() => this.setShowReportSetup(false)}
              size="lg"

              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>Report</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <Row>
                  <Col md={6}>
                    <ToggleButtonGroup name="report" vertical type="radio" value={this.state.report} onChange={this.handleReportChange}>
                      <ToggleButton variant="outline-dark" value={'daily'}>Daily Report</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-breakdown-rate-table'}>KPI Breakdown Rate Table</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-breakdown-rate-graph'}>KPI Breakdown Rate Graph</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-breakdown-time-table'}>KPI Breakdown Time Table</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-mean-time-to-repair-machine'}>KPI Mean Time to Repair Machine</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-mean-time-to-repair-machine-top5'}>KPI Mean Time to Repair Machine Top 5</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-mean-time-between-failure'}>KPI Mean Time Between Failure</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-mean-time-between-failure-top5'}>KPI Mean Time Between Failure Top 5</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-data-equipment-type'}>KPI Data Equipment Type</ToggleButton>
                      <ToggleButton variant="outline-dark" value={'kpi-working-time-for-personal'}>KPI Working Time For Personal</ToggleButton>
                    </ToggleButtonGroup>
                  </Col>
                  <Col>
                    <Row>
                      <Col md={1}>
                        From:
                            </Col>
                      <Col md={4}>
                        <div style={{ backgroundColor: '#ffffff' }}>
                          <DatePicker
                            format="dd/MM/y"
                            onChange={this.handleFromDateChange}
                            value={this.state.fromDate} />
                        </div>
                      </Col>
                    </Row>
                    <Row>
                      <Col md={1}>
                        To:
                            </Col>
                      <Col md={4}>
                        <div style={{ backgroundColor: '#ffffff' }}>
                          <DatePicker
                            format="dd/MM/y"
                            onChange={this.handleToDateChange}
                            value={this.state.toDate} />
                        </div>
                      </Col>
                    </Row>
                    <Row></Row>
                    <Row>
                      <Col md={1}></Col>
                      <Col md={4}>
                        {/* <Button block variant="outline-dark">Today</Button> */}
                        <a href='#' onClick={this.setToday}>เลือกวันนี้</a>
                        <br />
                        <br />
                        <Button block variant="secondary" onClick={this.showReport}>Generate</Button>
                      </Col>
                    </Row>
                  </Col>
                </Row>
              </Modal.Body>
              <Modal.Footer>

              </Modal.Footer>
            </Modal >

            <Modal
              show={this.state._showReportSetup}
              onHide={() => this.setShowReportSetup(false)}
              size="lg"

              aria-labelledby="contained-modal-title-vcenter"
              keyboard>
              <Modal.Header closeButton>
                <Modal.Title>Report</Modal.Title>
              </Modal.Header>
              <Modal.Body>
                <Tab.Container id="left-tabs-example" defaultActiveKey="report-daily">
                  <Row style={{ height: '40vh' }}>
                    <Col sm={3}>
                      <Nav variant="pills" className="flex-column">
                        <Nav.Item>
                          <Nav.Link eventKey="report-daily">Daily</Nav.Link>
                        </Nav.Item>
                        <Nav.Item>
                          <Nav.Link eventKey="report-kpi">KPI</Nav.Link>
                        </Nav.Item>
                      </Nav>
                    </Col>
                    <Col sm={9}>
                      <Tab.Content>
                        <Tab.Pane eventKey="report-daily">
                          <Row>
                            <Col md={1}>
                              From:
                            </Col>
                            <Col md={4}>
                              <div style={{ backgroundColor: '#ffffff' }}>
                                <DatePicker
                                  format="dd/MM/y"
                                  onChange={this.handleFromDateChange}
                                  value={this.state.fromDate} />
                              </div>
                            </Col>
                          </Row>
                          <Row>
                            <Col md={1}>
                              To:
                            </Col>
                            <Col md={4}>
                              <div style={{ backgroundColor: '#ffffff' }}>
                                <DatePicker
                                  format="dd/MM/y"
                                  onChange={this.handleToDateChange}
                                  value={this.state.toDate} />
                              </div>
                            </Col>
                          </Row>
                          <Row></Row>
                          <Row>
                            <Col md={1}></Col>
                            <Col md={4}>
                              {/* <Button block variant="outline-dark">Today</Button> */}
                              <a href='#' onClick={this.setToday}>เลือกวันนี้</a>
                              <br />
                              <br />
                              <Button block variant="secondary" onClick={() => this.setShowDailyReport(true)}>Generate</Button>
                            </Col>
                          </Row>

                        </Tab.Pane>
                        <Tab.Pane eventKey="report-kpi">
                          KPI
                        </Tab.Pane>
                      </Tab.Content>
                    </Col>
                  </Row>
                </Tab.Container>


              </Modal.Body>
              <Modal.Footer>

              </Modal.Footer>
            </Modal >



          </DataContext.Provider>
        </>
      );
    }
  }


}
