import React from 'react';
import {
    Container,
    Row, Col,
    Modal,
    Button,
    Form,
    // Table, Pagination, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';
import { css } from '@emotion/core';
import PropTypes from 'prop-types';
// import UserForm from '../forms/UserForm';
// import UserPasswordForm from '../forms/UserPasswordForm';
import GridLoader from 'react-spinners/GridLoader'; // https://www.react-spinners.com/
import Select from "react-select"; // https://github.com/JedWatson/react-select
import { DataContext } from '../data-context';
import ReactDataGrid from "react-data-grid";
import {
    Menu, Data, Filters, Toolbar,
    // ToolsPanel 
} from "react-data-grid-addons";

import {
    FaTrash, FaEdit,
    FaPlus, FaKey,
    // FaTimes, 
    // FaPhoneSquare, FaFax, FaRegEnvelope, 
    // FaAngleLeft, FaAngleRight
} from 'react-icons/fa';

const {
    ContextMenu, MenuItem,
    ContextMenuTrigger,
    // SubMenu, 
} = Menu;

const {
    AutoCompleteFilter,
    MultiSelectFilter,
    // NumericFilter,
    // SingleSelectFilter
} = Filters;

const override = css`
    display: block;
    margin: 0 auto;
    border-color: red;
    padding: 40px 0;
`;

const util = require('../util.js');
const apiUrl = process.env.REACT_APP_API_URL;

export default class Machine extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        data: PropTypes.array,
        loading: PropTypes.bool,
    };


    abortController = new AbortController();
    defaultColumnProperties = {
        filterable: false,
        sortable: true,
        // width: 120
    };
    selectors = Data.Selectors;

    columns = [
        { key: "name", name: "Name", filterable: true, filterRenderer: AutoCompleteFilter },
        { key: "code", name: "Code", width: 100, sortDescendingFirst: false, filterable: true, filterRenderer: AutoCompleteFilter, cellClass: 'center' },
        { key: "line", name: "Line", width: 100, sortDescendingFirst: false, filterable: true, filterRenderer: AutoCompleteFilter, cellClass: 'center' },
        { key: "depCode", name: "Dep", width: 100, sortDescendingFirst: false, filterable: true, filterRenderer: AutoCompleteFilter, cellClass: 'center' },
        // { key: "unit", name: "Unit/Div", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center', width: 100 },
        // { key: "email", name: "Email", filterable: true, filterRenderer: MultiSelectFilter, width: 200 },
        // { key: "tel1", name: "Tel 1", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
        // { key: "tel2", name: "Tel 2", filterable: true, filterRenderer: MultiSelectFilter, cellClass: 'center' },
    ];

    constructor(...args) {
        super(...args);

        let defaultColumnProperties = this.defaultColumnProperties;
        this.columns = this.columns.map(c => ({ ...defaultColumnProperties, ...c }));

        this.state = {
            // q: '',
            // user: null,
            machines: [],
            modeAdd: false,
            _id: '',
            code: '',
            name: '',
            line: '',
            depCode: '',
            loading: this.props.loading,
            depCodes: [
                { value: 'ASSY', label: 'ASSY' },
                { value: 'MFG', label: 'MFG' },
                { value: 'QC', label: 'QC' },
            ]
            // activePage: 1,
            // totalPages: 1,
            // totalmachines: 0,
            // itemsPerPage: 20,
            // showMessageModal: false,
            // messag: '',
            // showDetail: false,
            // showChangePassword: false,
            // showEdit: false,
            // showDeleteConfirm: false,
            // newRecord: false,
        }
    }

    UNSAFE_componentWillMount() {
        // componentDidMount() {
        let u0 = this.context.machines[0]
        console.log('u0', u0)
        let lines = []
        this.context.lines.forEach(v => {
            lines.push({
                value: v.name,
                label: v.name
            })
        })

        this.setState({
            machines: this.context.machines,            
            lines: lines,
            _id: u0._id,
            code: u0.code,
            name: u0.name,
            line: u0.line,
            depCode: u0.depCode,
            lineOption: { value: u0.line, label: u0.line },
            depCodeOption: { value: u0.depCode, label: u0.depCode },

        })
        // console.log("----.machines", this.context.machines)
        // this.fetchTotalmachines();
        // this.fetchmachines();
        // this.fetchmachines()
    }


    handleChange = (e) => {
        console.log([e.target.id], e.target.value, e.target.checked, e.target.type)
        if (e.target.type === 'checkbox') {
            this.setState({ [e.target.id]: e.target.checked })
        } else {
            this.setState({ [e.target.id]: e.target.value })
        }
    }

    handleAdd = (e) => {
        let code = this.state.code;
        let name = this.state.name;
        let machines = this.state.machines;
        let line = this.state.line;
        let depCode = this.state.depCode;

        // Confirm that there's no existing code
        for (let i = 0; i < machines.length; i++) {
            let u = machines[i]
            if (code === u.code) {
                alert('มีรหัสผู้ใช้นี้อยู่แล้ว')
                return
            }
        }

        util.saveMachine({
            code: code,
            name: name,
            line: line,
            depCode: depCode
        }).then(res => {
            alert(`เพิ่มข้อมูลผู้ใช้ใหม่แล้ว ${code} ${name}`)
            util.fetchMachines().then(res => {
                let machines = res.data
                this.context.machines = machines
                this.setState({
                    machines: machines
                })
            })
        }).catch(err => {
            alert('เกิดความผิดพลาดในการเพิ่มข้อมูล\n' + err)
            console.error(err)
        })

        this.setState({
            _id: '',
            code: '',
            name: '',
            modeAdd: false,
        })
    }

    handleCancelAdd = (e) => {
        let u0 = this.state.machines[0]
        this.setState({
            modeAdd: false,
            _id: '',
            code: u0.code,
            name: u0.name,
            line: u0.line,
            depCode: u0.depCode,
        })
    }

    handleUpdate = (e) => {
        let _id = this.state._id;
        let code = this.state.code;
        let name = this.state.name;
        let machines = this.state.machines;
        let line = this.state.line;
        let depCode = this.state.depCode;

        // console.log(_id)

        // Confirm that there's no existing code
        for (let i = 0; i < machines.length; i++) {
            let u = machines[i]
            if (code === u.code && _id !== u._id) {
                alert('มีรหัสผู้ใช้นี้อยู่แล้ว')
                return
            }
        }

        this.setState({ loading: true })
        util.updateMachine({
            _id: _id,
            code: code,
            name: name,
            line: line,
            depCode: depCode,
        }).then(res => {
            util.fetchMachines().then(res => {
                let machines = res.data
                this.context.machines = machines
                this.setState({
                    machines: machines,
                    loading: false
                })
            })

            console.log('Updated ', res)
            alert(`แก้ไข้อมูลผู้ใช้ใหม่แล้ว ${code} ${name}`)

        }).catch(err => {
            alert('เกิดความผิดพลาดในการแก้ไขข้อมูล\n' + err)
            console.error(err)
        })

        this.setState({
            // leave data in the form
            modeAdd: false,
        })
    }

    handleRowClick = (id, machine) => {
        console.log(machine)
        if (machine)
            this.setState({
                _id: machine._id,
                code: machine.code,
                name: machine.name,
                line: machine.line,
                depCode: machine.depCode,
                lineOption: { value: machine.line, label: machine.line },
                depCodeOption: { value: machine.depCode, label: machine.depCode },
            })
    }

    handleDelete = (event) => {
        if (window.confirm(`ยืนยันว่าต้องการลบ ${this.state.name}`)) {
            let _id = this.state._id
            util.deleteMachineById(_id).then(res => {
                alert("ลบแล้ว")
                util.fetchMachines().then(res => {
                    let machines = res.data
                    this.context.machines = machines
                    let u0 = machines[0]
                    this.setState({
                        machines: machines,
                        _id: u0._id,
                        code: u0.code,
                        name: u0.name,
                        line: u0.line,
                        depCode: u0.depCode,
                        modeAdd: false,
                    })
                })
            }).catch(err => {
                alert('เกิดความผิดพลาด\n' + err)
            })
        }
    }



    editHandler = (rowInx) => {
        this.showDetail(this.state.machines[rowInx])
    }

    changePasswordHandler = (rowInx) => {
        this.changePassword(this.state.machines[rowInx])
    }



    addHandler = () => {
        this.setState({
            modeAdd: true,
            code: '',
            name: '',
            line: '',
            depCode: '',
            lineOption: this.state.lines[0],
            depCodeOption: this.state.depCodes[0],
        });
    }

    searchChangeHandler = (e) => {
        this.setState({ q: e.target.value });
    }

    clearSearch = (e) => {
        let _this = this;
        this.setState(
            { q: '' },
            () => {
                _this.searchmachines();
            }
        );

    }

    ___searchmachines = () => {
        let q = this.state.q;
        console.log("Searching ", q);
        this.fetchMachines(q);
    }

    handleFilterChange = filter => {
        let filters = this.state.filters;
        const newFilters = { ...filters };
        if (filter.filterTerm) {
            newFilters[filter.column.key] = filter;
        } else {
            delete newFilters[filter.column.key];
        }
        return newFilters;
    };

    getValidFilterValues = (rows, columnId) => {
        return rows
            .map(r => r[columnId])
            .filter((item, i, a) => {
                return i === a.indexOf(item);
            });
    }


    getRows = (rows, filters) => {
        // console.log('filters', filters)
        return this.selectors.getRows({ rows, filters });
    }

    sortRows = (initialRows, sortColumn, sortDirection) => {
        console.log("sortRows")
        let rows = this.state.machines;
        const comparer = (a, b) => {
            if (sortDirection === "ASC") {
                return a[sortColumn] > b[sortColumn] ? 1 : -1;
            } else if (sortDirection === "DESC") {
                return a[sortColumn] < b[sortColumn] ? 1 : -1;
            }
        };
        return sortDirection === "NONE" ? initialRows : [...rows].sort(comparer);
    }

    handleLineSelect = (selectedOption) => {
        console.log("line", selectedOption.value)
        this.setState({
            line: selectedOption.value,
            lineOption: selectedOption
        })
    }

    handleDepCodeSelect = (selectedOption) => {
        console.log("line", selectedOption.value)
        this.setState({
            depCode: selectedOption.value,
            depCodeOption: selectedOption
        })
    }


    render() {
        let filteredRows = this.getRows(this.state.machines, this.state.filters);

        if (this.props.loading) {
            return (
                <GridLoader
                    css={override}
                    // sizeUnit={"px"}
                    // size={8}
                    color={'#4A90E2'}
                    loading={true}
                />
            );

        } else {
            let title = this.state.modeAdd ? 'เพิ่ม Machine ใหม่' : 'แก้ไขข้อมูล Machine ';
            return (
                <>
                    <Container fluid>

                        {/* <Row>
                        <Col>
                            <InputGroup className="mb-3">
                                <FormControl
                                    placeholder="ค้นหาด้วยชื่อ"
                                    aria-label="ค้นหาด้วยชื่อ"
                                    aria-describedby="basic-addon2"
                                    value={this.state.q}
                                    onChange={this.searchChangeHandler}
                                    onKeyPress={event => {
                                        if (event.key === "Enter") {
                                            this.searchmachines();
                                        }
                                    }}
                                />
                                <InputGroup.Append>
                                    <Button variant="outline-secondary"
                                        onClick={this.searchmachines}>
                                        ค้นหา
                                </Button>
                                    <Button variant="outline-secondary"
                                        onClick={this.clearSearch}>
                                        <FaTimes />
                                    </Button>
                                </InputGroup.Append>
                            </InputGroup>

                        </Col>
                    </Row> */}
                        <Row style={{ minHeight: '80vh'}}>
                            <Col md={7} style={{ backgroundColor: '#ffffff' }}>
                                {this.state.loading &&
                                    <GridLoader
                                        css={override}
                                        sizeUnit={"px"}
                                        size={60}
                                        color={'#4A90E2'}
                                        loading={true}
                                    />
                                }
                                {!this.state.loading &&
                                    <ReactDataGrid

                                        columns={this.columns}
                                        rowGetter={i => filteredRows[i]}
                                        rowsCount={filteredRows.length}
                                        onRowClick={this.handleRowClick}
                                        // minWidth={1024}
                                        minHeight={'70vh'}
                                        onGridSort={(sortColumn, sortDirection) =>
                                            this.setState({
                                                machines: this.sortRows(this.state.machines, sortColumn, sortDirection)
                                            })
                                        }
                                        RowsContainer={ContextMenuTrigger}
                                        emptyRowsView={this.EmptyRowsView}
                                        toolbar={
                                            <Toolbar enableFilter={true}>
                                                {/* <ButtonGroup aria-label="Basic example">
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(0)}>
                                        View All
                                </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(1)}>
                                        A
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(2)}>
                                        B
                                    </Button>
                                    <Button variant="outline" onClick={() => this.fetchPartsByStatus(3)}>
                                        C
                                    </Button>
                                </ButtonGroup> */}
                                            </Toolbar>
                                        }
                                        onAddFilter={filter => this.setState({ filters: this.handleFilterChange(filter) })}
                                        onClearFilters={() => this.setState({ filters: {} })}
                                        getValidFilterValues={columnKey => this.getValidFilterValues(this.state.machines, columnKey)}
                                    />
                                }
                            </Col>
                            <Col md={5} style={{ backgroundColor: '#ffffff' }}>
                                <Row>
                                    <Col>
                                        <h2>{title}</h2>
                                    </Col>
                                    <Col sm={4} style={{ textAlign: 'right' }}>
                                        <Button variant="success" onClick={this.addHandler}><FaPlus /> เพิ่ม Machine </Button>
                                    </Col>
                                </Row>
                                <Form disabled={this.viewMode}>

                                    <Form.Group>
                                        <Form.Label>Code</Form.Label>
                                        <Form.Control
                                            id="code"
                                            type="text"
                                            required
                                            onChange={this.handleChange}
                                            value={this.state.code} />
                                    </Form.Group>
                                    <Form.Group>
                                        <Form.Label>Name</Form.Label>
                                        <Form.Control
                                            id="name"
                                            type="text"
                                            required
                                            onChange={this.handleChange}
                                            value={this.state.name} />
                                    </Form.Group>
                                    <Form.Group>
                                        Line
                                        <Select
                                            value={this.state.lineOption}
                                            options={this.state.lines}
                                            onChange={this.handleLineSelect} />
                                    </Form.Group>

                                    <Form.Group>
                                        Department
                                        <Select
                                            value={this.state.depCodeOption}
                                            options={this.state.depCodes}
                                            onChange={this.handleDepCodeSelect} />
                                    </Form.Group>

                                    {this.state.modeAdd && <Button variant="primary" onClick={this.handleAdd}>เพิ่มผู้ใช้</Button>}
                                    {this.state.modeAdd && <Button variant="secondary" onClick={this.handleCancelAdd}>ยกเลิก</Button>}
                                    {!this.state.modeAdd && <Button onClick={this.handleUpdate}>บันทึกข้อมูล</Button>}
                                    {!this.state.modeAdd && <Button variant="danger" onClick={this.handleDelete}>ลบ Machine </Button>}
                                </Form>
                            </Col>
                        </Row>

                    </Container>

                    {/* <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showDetail}
                        onHide={this.closeDetail}                    >
                        <Modal.Header closeButton>
                            <Modal.Title id="contained-modal-title-vcenter">
                                รายละเอียด Line 
                    </Modal.Title>
                        </Modal.Header>
                        <Modal.Body>
                            <UserForm
                                newRecord={this.state.newRecord}
                                closeFormHandler={this.closeDetail}
                                data={this.state.user}
                            />
                        </Modal.Body>
                    </Modal>

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showChangePassword}
                        onHide={this.closeChangePassword}                    >
                        <Modal.Header closeButton>
                            <Modal.Title id="contained-modal-title-vcenter">
                                เปลี่ยนรหัสผ่าน
                    </Modal.Title>
                        </Modal.Header>
                        <Modal.Body>
                            <UserPasswordForm
                                closeFormHandler={this.closeChangePassword}
                                user={this.state.user}
                            />
                        </Modal.Body>
                    </Modal>

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showDeleteConfirm}
                        onHide={() => this.setState({ showDeleteConfirm: false })}
                    >

                        <Modal.Body>
                            ยืนยันลบข้อมูล {this.userToDelete.name}
                        </Modal.Body>
                        <Modal.Footer>
                            <Button variant="danger" onClick={() => this.deleteHandler(this.userToDelete._id)}>ลบ</Button>
                            <Button variant="outline-secondary" onClick={() => this.setState({ showDeleteConfirm: false })}>ยกเลิก</Button>
                        </Modal.Footer>
                    </Modal> */}

                    <Modal
                        size="lg"
                        aria-labelledby="contained-modal-title-vcenter"
                        centered
                        show={this.state.showMessageModal}
                        onHide={() => this.setState({ showMessageModal: false })}
                    >
                        <Modal.Body>
                            {this.state.message}
                        </Modal.Body>
                        <Modal.Footer>
                            <Button variant="outline-secondary" onClick={() => this.setState({ showMessageModal: false })}>
                                ปิด
                            </Button>
                        </Modal.Footer>
                    </Modal>
                </>
            );
        }
    }
}
